def extract_features(filepath):
    df = pd.read_parquet(filepath)
    if len(df) == 0:
        return None
    return {
        'n_logins': int((df['action'] == 1).sum()),
        'n_get': int((df['action'] == 2).sum()),
        'n_post': int((df['action'] == 3).sum()),
        'n_put': int((df['action'] == 4).sum()),
        'n_actions': len(df),
        'n_days': int(df['timestamp'].dt.date.nunique()),
    }

